const DAYS_AGO = 60;
const usernames = [...new Set($input.all().map(item => String(item.json.username || '').trim()).filter(Boolean))];
if (usernames.length === 0) { return [{ json: { should_continue: false, scheduler_alert_type: 'NO_TRACKED_USERS', message: 'Scheduled tracking ran with no tracked users configured.' } }]; }
const startDate = new Date();
startDate.setUTCDate(startDate.getUTCDate() - DAYS_AGO);
return [{ json: { should_continue: true, query: usernames.map(username => `from:${username}`).join(' OR '), start_time: startDate.toISOString(), usernames, user_count: usernames.length } }];

const state = $('Advance Post Suppression State').first()?.json || {};
const rawBlocked = state.blocked_post_ids || [];

let blockedIds = [];
if (Array.isArray(rawBlocked)) {
  blockedIds = rawBlocked;
} else if (typeof rawBlocked === 'string') {
  blockedIds = rawBlocked
    .replace(/^\{/, '')
    .replace(/\}$/, '')
    .split(',')
    .map(value => value.replace(/^"|"$/g, '').trim())
    .filter(Boolean);
}

const blocked = new Set(blockedIds.map(String));
return $input.all().filter(item => !blocked.has(String(item.json.id || '')));

const conversationIds = [...new Set(
  $input.all()
    .map(item => String(item.json.conversation_id || '').trim())
    .filter(Boolean)
)];

if (conversationIds.length === 0) {
  return [];
}

return [{
  json: {
    query: conversationIds
      .map(id => `(conversation_id:${id} is:reply)`)
      .join(' OR '),
    conversation_ids: conversationIds,
    conversation_count: conversationIds.length,
  },
}];

const postsByConversation = new Map(
  $('Keep Posts With 10+ Replies').all().map(item => [
    String(item.json.conversation_id),
    {
      postId: item.json.id,
      postText: item.json.text,
      userId: item.json.author_id,
      replies: [],
    },
  ])
);

for (const group of $('Get Replies').all()) {
  for (const reply of group.json.data || []) {
    const post = postsByConversation.get(String(reply.conversation_id));
    if (!post || !reply.id) continue;

    post.replies.push({
      id: reply.id,
      text: String(reply.text || '').replace(/\s+/g, ' ').trim(),
    });
  }
}

return [{
  json: {
    text: JSON.stringify({ results: [...postsByConversation.values()] }),
  },
}];

function parseResults(item) {
  const candidates = [
    item.json?.output?.[0]?.content?.[0]?.text,
    item.json?.output,
    item.json?.text,
  ];

  for (const candidate of candidates) {
    let value = candidate;
    if (typeof value === 'string') {
      try {
        value = JSON.parse(value);
      } catch {
        continue;
      }
    }

    if (Array.isArray(value?.results)) {
      return value.results;
    }
  }

  throw new Error('OpenAI response did not contain a results array.');
}

return items.map(item => {
  const posts = parseResults(item).map(post => {
    const replies = Array.isArray(post.replies) ? post.replies : [];
    const counts = { positive: 0, neutral: 0, negative: 0 };

    for (const reply of replies) {
      const sentiment = String(reply.sentiment || '').toLowerCase();
      if (Object.prototype.hasOwnProperty.call(counts, sentiment)) {
        counts[sentiment] += 1;
      }
    }

    const comments_count = replies.length;
    const negative_ratio = comments_count > 0
      ? counts.negative / comments_count
      : 0;

    let overall_tag = 'Neutral';
    if (counts.positive > counts.neutral && counts.positive > counts.negative) {
      overall_tag = 'Positive';
    } else if (counts.negative > counts.neutral && counts.negative > counts.positive) {
      overall_tag = 'Negative';
    }

    return {
      postId: post.postId,
      postText: post.postText,
      userId: post.userId,
      replies,
      comments_count,
      positive_count: counts.positive,
      neutral_count: counts.neutral,
      negative_count: counts.negative,
      negative_ratio,
      negative_percentage: Math.round(negative_ratio * 100),
      overall_tag,
    };
  });

  return {
    json: {
      posts: posts.filter(post => post.negative_ratio >= 0.5),
    },
  };
});

const allPosts = $("Split Out Reply Analysis").all();

const allReplies = allPosts.flatMap(post => {
  const replies = post.json.replies || [];
  return replies.map(reply => ({
    ...reply,
    postId: post.json.postId,
    postText: post.json.postText
  }));
});

return allReplies.map(reply => ({ json: reply }));

